                            <span className="text-xs font-bold text-cyan-300 tracking-wider font-mono drop-shadow-sm">TIME ENGINE</span>
                        </div>
                        <span className="text-[10px] font-bold text-cyan-100/70 ml-4 font-mono">时光引擎</span>
                    </div>

                    {/* Content Row */}
