        {/* 轨道线 (Orbit Line) */}
        <mesh rotation={[Math.PI / 2, 0, 0]}>
           <ringGeometry args={[1.38, 1.42, 64]} />
           <meshBasicMaterial color="#38bdf8" opacity={0.3} transparent side={DoubleSide} />
        </mesh>
      </group>
    </group>
  );
};

