  simulationSpeed: number;
}> = ({ name, size, distance, speed, color, type, isPaused, simulationSpeed }) => {
  const ref = useRef<Group>(null);

  const textureUrl = useMemo(() => generatePlanetTexture({
    id: type, // ID matches the type for texture generation
    name: name,
    color: color,
    size: size,
    distance: 0,
    realDistance: 0,
