    description: '',
    textureConfig: {
      type: type,
      colors: [color, color, color] // Colors are handled inside textureGenerator for these types
    }
  }), [type, name, color, size]);

  const texture = useMemo(() => new TextureLoader().load(textureUrl), [textureUrl]);

  useFrame((state, delta) => {
    if (ref.current && !isPaused) {
      ref.current.rotation.y += delta * speed * simulationSpeed;
