export const Planet: React.FC<PlanetProps> = ({ 
  data, 
  isSelected, 
  onSelect, 
  isPaused,
  simulationSpeed,
  earthPositionRef,
  planetRefs,
  isStarshipActive
}) => {
  const meshRef = useRef<Mesh>(null);
  const orbitGroupRef = useRef<Group>(null);
  const inclinationGroupRef = useRef<Group>(null); // New group for orbital inclination
  const distanceLabelRef = useRef<HTMLSpanElement>(null);
  const [hovered, setHovered] = useState(false);

  // Register this planet to the refs map for the Starship
  useEffect(() => {
    // We register the planet's internal orbit position group (orbitGroupRef)
    // so the starship flies to where the planet IS.
    if (orbitGroupRef.current) {
      planetRefs.current[data.id] = orbitGroupRef.current;
    }
  }, [data.id, planetRefs]);

  // Use a Ref to track orbit angle so we can pause/resume smoothly
  const orbitAngleRef = useRef(Math.random() * Math.PI * 2);

  // Generate SVG Texture for Surface
  const textureUrl = useMemo(() => generatePlanetTexture(data), [data]);
  const texture = useMemo(() => new TextureLoader().load(textureUrl), [textureUrl]);

  // Generate SVG Texture for Rings (if applicable)
  const ringTextureUrl = useMemo(() => {
    return data.hasRings && data.ringColor ? generateRingTexture(data.id, data.ringColor) : null;
  }, [data]);
  const ringTexture = useMemo(() => ringTextureUrl ? new TextureLoader().load(ringTextureUrl) : null, [ringTextureUrl]);

  // Generate Generic Soft Glow Texture for Atmosphere
  const glowTextureUrl = useMemo(() => data.atmosphereColor ? generateGenericGlowTexture() : null, [data.atmosphereColor]);
  const glowTexture = useMemo(() => glowTextureUrl ? new TextureLoader().load(glowTextureUrl) : null, [glowTextureUrl]);

  useFrame((state, delta) => {
    if (!orbitGroupRef.current || !meshRef.current) return;

    if (!isPaused) {
      // Orbit logic - Update Accumulator
      // Reduced base speed multiplier from 0.2 to 0.1 for slower 1x simulation
      orbitAngleRef.current += delta * data.speed * 0.1 * simulationSpeed;

      // Counter-Clockwise Revolution:
      // x = cos(angle), z = -sin(angle)
      const x = Math.cos(orbitAngleRef.current) * data.distance;
      const z = -Math.sin(orbitAngleRef.current) * data.distance;

      // The orbitGroupRef moves in a flat circle relative to its parent (the Inclination Group)
      orbitGroupRef.current.position.set(x, 0, z);

      // Self rotation logic
      meshRef.current.rotation.y += data.rotationSpeed * simulationSpeed;

      // Update Earth's position ref if this is Earth
      // NOTE: We need the WORLD position since we are now nesting groups
      if (data.id === 'earth') {
        // Using getWorldPosition because of the nested groups (inclination > orbit > planet)
        orbitGroupRef.current.getWorldPosition(earthPositionRef.current);
      }
    }

    // Update Distance Label continuously while hovered
    if (hovered && distanceLabelRef.current && data.id !== 'earth') {
      // Need world positions for accurate distance
      const thisPos = new Vector3();
      orbitGroupRef.current.getWorldPosition(thisPos);

      // earthPositionRef is already tracking Earth's world pos
      const dist = thisPos.distanceTo(earthPositionRef.current);
      if (isNaN(dist)) return;

      const millionKm = dist * 7.14;
      const wanKm = millionKm * 100;

      distanceLabelRef.current.innerText = `距离地球: ${Math.round(wanKm).toLocaleString()} 万公里`;
    }
  });

  return (
    // Outer Group: Applies Orbital Inclination (The tilt of the entire orbit path)
    // We rotate around the Z axis to tilt the plane left/right relative to the sun
    <group ref={inclinationGroupRef} rotation={[0, 0, data.orbitInclination || 0]}>

      {/* Orbit Path Visual (Ring) - Stays static within the inclined plane */}
      {/* HIDE when Starship is active for cleaner look */}
      <mesh rotation={[-Math.PI / 2, 0, 0]} visible={!isStarshipActive}>
        <ringGeometry args={[data.distance - 0.05, data.distance + 0.05, 128]} />
        <meshBasicMaterial color="#ffffff" opacity={0.35} transparent side={DoubleSide} />
      </mesh>

      {/* The Planet Group - Moves along the orbit path */}
      <group ref={orbitGroupRef}>

        {/* Axial Tilt Group - Apply planet's specific self-tilt here */}
        <group rotation={[0, 0, data.axisTilt || 0]}>

          {/* Main Planet Sphere - Rotation (Day/Night) happens here */}
          <mesh
            ref={meshRef}
            onClick={(e) => {
              e.stopPropagation();
              onSelect(data.id);
            }}
            onPointerOver={() => {
              document.body.style.cursor = 'pointer';
              setHovered(true);
            }}
            onPointerOut={() => {
              document.body.style.cursor = 'auto';
              setHovered(false);
            }}
          >
            <sphereGeometry args={[data.size, 64, 64]} />
            <meshPhysicalMaterial 
              map={texture}
              color="#ffffff" 
              roughness={0.6}
              metalness={0.2}
              clearcoat={0.3}
              clearcoatRoughness={0.4}
              emissive={isSelected || hovered ? new Color(data.color) : new Color('#000000')}
              emissiveIntensity={isSelected || hovered ? 0.4 : 0}
            />

            {/* Planet Label - ONLY SHOW ON HOVER */}
            {hovered && (
              <Html position={[0, data.size + 3.0, 0]} center zIndexRange={[100, 0]} style={{ pointerEvents: 'none' }}>
                <div className="flex flex-col items-center gap-2 pointer-events-none select-none transition-all duration-200">
                  <div className="bg-black/80 text-white px-4 py-2 rounded-xl text-sm whitespace-nowrap border border-white/30 backdrop-blur-sm font-bold shadow-[0_4px_20px_rgba(0,0,0,0.5)] animate-fade-in-up">
                    {data.name}
                  </div>
                  {/* Dynamic Distance Label */}
                  {data.id !== 'earth' && (
                      <div className="bg-blue-600/80 text-blue-50 px-3 py-1 rounded-full text-xs whitespace-nowrap border border-blue-300/50 backdrop-blur-sm shadow-lg font-mono tracking-wide">
                        <span ref={distanceLabelRef}>计算距离...</span>
                      </div>
                  )}
                </div>
              </Html>
            )}
          </mesh>

          {/* Rings - Tilted with the planet */}
          {data.hasRings && ringTexture && (
            // Rotate X by -90 to lay flat relative to the tilted group
            <mesh rotation={[-Math.PI / 2, 0, 0]}>
              <ringGeometry args={[data.size * 1.4, data.size * 2.3, 128]} />
              <meshStandardMaterial 
                map={ringTexture}
                color="#ffffff" 
                opacity={0.9} 
                transparent 
                side={DoubleSide} 
                roughness={0.4}
                metalness={0.2}
              />
            </mesh>
          )}
        </group>

        {/* --- EARTH SPECIFIC SATELLITES --- */}
        {data.id === 'earth' && (
          <>
            {/* Moon: Placed outside the axial tilt group so it orbits the center of Earth's position */}
            <Moon isPaused={isPaused} simulationSpeed={simulationSpeed} />

            {/* Tiangong Space Station: Lower orbit than Moon */}
            <TiangongStation isPaused={isPaused} simulationSpeed={simulationSpeed} />
          </>
        )}

        {/* --- JUPITER SPECIFIC SATELLITES (GALILEAN MOONS) --- */}
        {data.id === 'jupiter' && (
           <JupiterMoons 
             isPaused={isPaused} 
             simulationSpeed={simulationSpeed}
             onSelect={onSelect}
             selectedId={isSelected ? data.id : null} // Simple pass-through check, handled better in App state
           />
        )}

        {/* Atmosphere Glow Shell (Billboard) - Replaced Shader with Sprite/Billboard method */}
        {/* We place it OUTSIDE the tilted group so it stays upright facing the camera properly, but follows position */}
        {data.atmosphereColor && glowTexture && (
           <Billboard>
              {/* Scale it up ~2.8x the planet size for a soft diffuse glow */}
              <mesh scale={[data.size * 2.8, data.size * 2.8, 1]}>
                <planeGeometry args={[1, 1]} />
                <meshBasicMaterial 
                  map={glowTexture} 
                  transparent 
                  opacity={0.25} // Low opacity for subtle effect
                  depthWrite={false}
                  blending={AdditiveBlending}
                  color={new Color(data.atmosphereColor)}
                />
              </mesh>
           </Billboard>
        )}

      </group>
    </group>
  );
};

import React, { useState, Suspense, useRef, useMemo, useEffect } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, Sparkles, PerspectiveCamera, Environment, Stars } from '@react-three/drei';
import { Vector3, TextureLoader, BackSide, Mesh, Object3D, RepeatWrapping, ClampToEdgeWrapping, MathUtils } from 'three';
import { PLANETS, SUN_DATA, JUPITER_MOONS } from './constants';
import { Planet } from './components/Planet';
import { Sun } from './components/Sun';
import { Starship } from './components/Starship';
import { AsteroidBelt } from './components/AsteroidBelt';
import { UIOverlay } from './components/UIOverlay';
import { GestureController } from './components/GestureController';
import { generateStarFieldTexture } from './utils/textureGenerator';

const Skybox: React.FC = () => {
  const meshRef = useRef<Mesh>(null);
  const starTextureUrl = useMemo(() => generateStarFieldTexture(), []);
  const starTexture = useMemo(() => {
    const t = new TextureLoader().load(starTextureUrl);
    t.wrapS = RepeatWrapping;
    t.wrapT = ClampToEdgeWrapping; 
    return t;
  }, [starTextureUrl]);

  useFrame((state, delta) => {
    if (meshRef.current) {
      meshRef.current.rotation.y += delta * 0.0001; // Slower background rotation
    }
  });

  return (
    <mesh ref={meshRef}>
      <sphereGeometry args={[500, 64, 64]} />
      <meshBasicMaterial 
        map={starTexture} 
        side={BackSide} 
        color="#ffffff"
      />
    </mesh>
  );
};

// Updated Controller with Smoothing to prevent Jitter
const OrbitController = ({ controlsRef, gestureVelocity }: { controlsRef: any, gestureVelocity: React.MutableRefObject<{dx: number, dy: number, gestureType: 'rotate' | 'zoom'}> }) => {
  // Store smoothed values to prevent camera shaking from noisy hand data
  const smoothed = useRef({ dx: 0, dy: 0 });

  useFrame((state, delta) => {
    if (controlsRef.current && controlsRef.current.enabled) {
      const { dx, dy, gestureType } = gestureVelocity.current;

      // Smoothing factor: Lower = Smoother/Slower, Higher = More responsive/Jittery
      // 5.0 * delta gives a nice weighted average over ~0.2 seconds
      const smoothFactor = 5.0 * delta;

      smoothed.current.dx = MathUtils.lerp(smoothed.current.dx, dx, smoothFactor);
      smoothed.current.dy = MathUtils.lerp(smoothed.current.dy, dy, smoothFactor);

      // Use a small deadzone to stop movement completely when hands are steady
      const threshold = 0.001; 
      const activeDx = Math.abs(smoothed.current.dx) > threshold ? smoothed.current.dx : 0;
      const activeDy = Math.abs(smoothed.current.dy) > threshold ? smoothed.current.dy : 0;

      const isActive = activeDx !== 0 || activeDy !== 0;

      if (isActive) {
          if (gestureType === 'rotate') {
             // ROTATE MODE
             // Hand Left/Right (dx) -> Rotate Azimuth
             controlsRef.current.setAzimuthalAngle(controlsRef.current.getAzimuthalAngle() - activeDx * 0.02);

             // Hand Up/Down (dy) -> Rotate Polar Angle
             // Requirement: "Up movement -> Camera angle moves down"
             // Hand Up (dy < 0). 'activeDy' is negative.
             // We want Camera Down -> Increase Polar Angle (towards PI/2).
             // Subtracting negative activeDy adds to the angle.
             controlsRef.current.setPolarAngle(controlsRef.current.getPolarAngle() - activeDy * 0.02);

          } else if (gestureType === 'zoom') {
             // ZOOM MODE
             const zoomSensitivity = 0.015; // Adjusted sensitivity

             // Smooth zoom application
             const speed = 1.0 + Math.abs(activeDy * zoomSensitivity);

             // activeDy corresponds to change in distance between hands (Spread > 0, Close < 0)
             // Requirement: "Hands spread and lengthen distance -> view zooms in"
             if (activeDy > 0) {
                 // Spread -> Zoom In (Dolly In)
                 controlsRef.current.dollyIn(speed);
             } else {
                 // Close -> Zoom Out (Dolly Out)
                 controlsRef.current.dollyOut(speed);
             }
          }
          controlsRef.current.update();
      }
    }
  });
  return null;
}

const App: React.FC = () => {
  const [selectedPlanetId, setSelectedPlanetId] = useState<string | null>(null);
  const [isPaused, setIsPaused] = useState(false);
  const [simulationSpeed, setSimulationSpeed] = useState(1.0); 
  const [isStarshipActive, setIsStarshipActive] = useState(false);
  const [showPluto, setShowPluto] = useState(false);

  const [isGestureMode, setIsGestureMode] = useState(false);
  const [isARMode, setIsARMode] = useState(false); // AR Mode State

  const earthPositionRef = useRef<Vector3>(new Vector3(0, 0, 0));
  const planetRefs = useRef<{ [key: string]: Object3D }>({});
  const controlsRef = useRef<any>(null);

  const gestureVelocity = useRef<{dx: number, dy: number, gestureType: 'rotate' | 'zoom'}>({ dx: 0, dy: 0, gestureType: 'rotate' });

  // Safety Effect: Ensure body background is black on mount, and transparent on AR
  useEffect(() => {
    document.body.style.backgroundColor = isARMode ? 'transparent' : '#000';
    const root = document.getElementById('root');
    if (root) root.style.backgroundColor = isARMode ? 'transparent' : '#000';
  }, [isARMode]);

  const handleSelect = (id: string) => {
    setSelectedPlanetId(id);
    setIsPaused(true); 
  };

  const handleClose = () => {
    setSelectedPlanetId(null);
    setIsPaused(false); 
  };

  const togglePluto = () => {
    const newValue = !showPluto;
    setShowPluto(newValue);
    if (!newValue && selectedPlanetId === 'pluto') {
      handleClose();
    }
  };

  const handleGestureControl = (dx: number, dy: number, gestureType: 'rotate' | 'zoom') => {
    gestureVelocity.current = { dx, dy, gestureType };
  };

  const toggleGestureMode = () => {
    const nextState = !isGestureMode;
    setIsGestureMode(nextState);
    if (nextState) {
      setSimulationSpeed(1.0);
    } else {
      // If turning off gesture mode, also turn off AR
      setIsARMode(false);
    }
  };

  const handleToggleStarship = () => {
    const activating = !isStarshipActive;
    setIsStarshipActive(activating);
    if (activating) {
       setIsPaused(false);
       setSimulationSpeed(0.5); 
    } else {
       setSimulationSpeed(1.0);
    }
  };

  const handleMissionComplete = () => {
     setIsStarshipActive(false);
     setSimulationSpeed(1.0); 
  };

  const selectedPlanet = useMemo(() => {
    if (selectedPlanetId === 'sun') return SUN_DATA;
    // Check main planets
    const planet = PLANETS.find(p => p.id === selectedPlanetId);
    if (planet) return planet;
    // Check Jupiter's moons
    return JUPITER_MOONS.find(m => m.id === selectedPlanetId) || null;
  }, [selectedPlanetId]);

  const displayedPlanets = useMemo(() => {
    return showPluto ? PLANETS : PLANETS.filter(p => p.id !== 'pluto');
  }, [showPluto]);

  return (
    <div className="w-full h-screen relative overflow-hidden transition-colors duration-500"
         style={{ backgroundColor: isARMode ? 'transparent' : '#000' }}
    >

      <UIOverlay 
        selectedPlanet={selectedPlanet}
        onClose={handleClose}
        isPaused={isPaused}
        togglePause={() => setIsPaused(!isPaused)}
        simulationSpeed={simulationSpeed}
        setSimulationSpeed={setSimulationSpeed}
        isStarshipActive={isStarshipActive}
        toggleStarship={handleToggleStarship}
        showPluto={showPluto}
        togglePluto={togglePluto}
        isGestureMode={isGestureMode}
        toggleGestureMode={toggleGestureMode}
      />

      {isGestureMode && (
        <GestureController 
          onControl={handleGestureControl} 
          onClose={() => toggleGestureMode()} 
          isARMode={isARMode}
          toggleARMode={() => setIsARMode(!isARMode)}
        />
      )}

      {/* 
         Canvas needs alpha: true for transparency.
         When AR Mode is ON, we hide the Skybox and opaque layers so the video behind shows through.
      */}
      <Canvas gl={{ antialias: true, toneMappingExposure: 1.2, alpha: true }}>
        <Suspense fallback={null}>
          <PerspectiveCamera makeDefault position={[0, 80, 120]} fov={45} />

          <OrbitControls 
            ref={controlsRef}
            makeDefault
            enabled={!isStarshipActive} 
            enableDamping={true}
            dampingFactor={0.05}
            enablePan={false}
            minDistance={20}
            maxDistance={300}
            maxPolarAngle={Math.PI / 1.8}
            // Slower auto-rotate for better default experience
            autoRotate={!selectedPlanetId && !isPaused && !isGestureMode && !isStarshipActive}
            autoRotateSpeed={0.1 * simulationSpeed} 
          />

          <OrbitController controlsRef={controlsRef} gestureVelocity={gestureVelocity} />

          <Environment preset="city" environmentIntensity={0.3} />
          <pointLight position={[0, 0, 0]} intensity={2.5} distance={500} decay={1} color="#FFF5E0" />
          <ambientLight intensity={0.15} color="#404060" />

          {/* 1. Volumetric 3D Stars (Always show, they look nice floating in room) */}
          <Stars radius={400} depth={50} count={3000} factor={4} saturation={0.5} fade speed={0.5} />

          {/* 2. Painted Background (Skybox) - HIDE IN AR MODE */}
          {!isARMode && <Skybox />}

          {/* 3. Magical Dust */}
          <Sparkles count={400} scale={200} size={6} speed={0.2} opacity={0.4} noise={0.1} color="#88AAFF" />
          <Sparkles count={150} scale={150} size={3} speed={0.3} opacity={0.6} color="#FFD700" />

          <Sun 
             onSelect={handleSelect}
             isSelected={selectedPlanetId === 'sun'}
             isPaused={isPaused}
             simulationSpeed={simulationSpeed}
          />

          <AsteroidBelt isPaused={isPaused} simulationSpeed={simulationSpeed} />

          {displayedPlanets.map((planet) => (
            <Planet 
              key={planet.id} 
              data={planet} 
              isSelected={selectedPlanetId === planet.id}
              onSelect={handleSelect}
              isPaused={isPaused}
              simulationSpeed={simulationSpeed}
              earthPositionRef={earthPositionRef}
              planetRefs={planetRefs}
              isStarshipActive={isStarshipActive}
            />
          ))}

          {isStarshipActive && (
             <Starship 
                planetRefs={planetRefs} 
                onMissionComplete={handleMissionComplete}
             />
          )}

        </Suspense>
      </Canvas>
    </div>
  );
};

export default App;

import React from 'react';
import { PlanetData } from '../types';

interface UIOverlayProps {
  selectedPlanet: PlanetData | null;
  onClose: () => void;
  isPaused: boolean;
  togglePause: () => void;
  simulationSpeed: number;
  setSimulationSpeed: (speed: number) => void;
  isStarshipActive: boolean;
  toggleStarship: () => void;
  showPluto: boolean;
  togglePluto: () => void;
  toggleGestureMode: () => void;
  isGestureMode: boolean;
}

export const UIOverlay: React.FC<UIOverlayProps> = ({ 
  selectedPlanet, 
  onClose,
  isPaused,
  togglePause,
