// Updated Controller with Smoothing to prevent Jitter
const OrbitController = ({ controlsRef, gestureVelocity }: { controlsRef: any, gestureVelocity: React.MutableRefObject<{dx: number, dy: number, gestureType: 'rotate' | 'zoom'}> }) => {
  // Store smoothed values to prevent camera shaking from noisy hand data
  const smoothed = useRef({ dx: 0, dy: 0 });

  useFrame((state, delta) => {
    if (controlsRef.current && controlsRef.current.enabled) {
      const { dx, dy, gestureType } = gestureVelocity.current;

      // Smoothing factor: Lower = Smoother/Slower, Higher = More responsive/Jittery
      // 5.0 * delta gives a nice weighted average over ~0.2 seconds
      const smoothFactor = 5.0 * delta;

      smoothed.current.dx = MathUtils.lerp(smoothed.current.dx, dx, smoothFactor);
      smoothed.current.dy = MathUtils.lerp(smoothed.current.dy, dy, smoothFactor);

      // Use a small deadzone to stop movement completely when hands are steady
      const threshold = 0.001; 
      const activeDx = Math.abs(smoothed.current.dx) > threshold ? smoothed.current.dx : 0;
      const activeDy = Math.abs(smoothed.current.dy) > threshold ? smoothed.current.dy : 0;

      const isActive = activeDx !== 0 || activeDy !== 0;

      if (isActive) {
          if (gestureType === 'rotate') {
             // ROTATE MODE
             // Hand Left/Right (dx) -> Rotate Azimuth
             controlsRef.current.setAzimuthalAngle(controlsRef.current.getAzimuthalAngle() - activeDx * 0.02);

             // Hand Up/Down (dy) -> Rotate Polar Angle
             // Requirement: "Up movement -> Camera angle moves down"
             // Hand Up (dy < 0). 'activeDy' is negative.
             // We want Camera Down -> Increase Polar Angle (towards PI/2).
             // Subtracting negative activeDy adds to the angle.
             controlsRef.current.setPolarAngle(controlsRef.current.getPolarAngle() - activeDy * 0.02);

          } else if (gestureType === 'zoom') {
             // ZOOM MODE
             const zoomSensitivity = 0.015; // Adjusted sensitivity

             // Smooth zoom application
             const speed = 1.0 + Math.abs(activeDy * zoomSensitivity);

             // activeDy corresponds to change in distance between hands (Spread > 0, Close < 0)
             // Requirement: "Hands spread and lengthen distance -> view zooms in"
             if (activeDy > 0) {
                 // Spread -> Zoom In (Dolly In)
                 controlsRef.current.dollyIn(speed);
             } else {
                 // Close -> Zoom Out (Dolly Out)
                 controlsRef.current.dollyOut(speed);
             }
          }
          controlsRef.current.update();
      }
    }
  });
  return null;
}

const App: React.FC = () => {
  const [selectedPlanetId, setSelectedPlanetId] = useState<string | null>(null);
  const [isPaused, setIsPaused] = useState(false);
  const [simulationSpeed, setSimulationSpeed] = useState(1.0); 
  const [isStarshipActive, setIsStarshipActive] = useState(false);
  const [showPluto, setShowPluto] = useState(false);

  const [isGestureMode, setIsGestureMode] = useState(false);
  const [isARMode, setIsARMode] = useState(false); // AR Mode State

  const earthPositionRef = useRef<Vector3>(new Vector3(0, 0, 0));
  const planetRefs = useRef<{ [key: string]: Object3D }>({});
  const controlsRef = useRef<any>(null);

  const gestureVelocity = useRef<{dx: number, dy: number, gestureType: 'rotate' | 'zoom'}>({ dx: 0, dy: 0, gestureType: 'rotate' });

  // Safety Effect: Ensure body background is black on mount, and transparent on AR
  useEffect(() => {
    document.body.style.backgroundColor = isARMode ? 'transparent' : '#000';
    const root = document.getElementById('root');
    if (root) root.style.backgroundColor = isARMode ? 'transparent' : '#000';
  }, [isARMode]);

  const handleSelect = (id: string) => {
    setSelectedPlanetId(id);
    setIsPaused(true); 
  };

  const handleClose = () => {
    setSelectedPlanetId(null);
    setIsPaused(false); 
  };

  const togglePluto = () => {
    const newValue = !showPluto;
    setShowPluto(newValue);
    if (!newValue && selectedPlanetId === 'pluto') {
      handleClose();
    }
  };

  const handleGestureControl = (dx: number, dy: number, gestureType: 'rotate' | 'zoom') => {
    gestureVelocity.current = { dx, dy, gestureType };
  };

  const toggleGestureMode = () => {
    const nextState = !isGestureMode;
    setIsGestureMode(nextState);
    if (nextState) {
      setSimulationSpeed(1.0);
    } else {
      // If turning off gesture mode, also turn off AR
      setIsARMode(false);
    }
  };

  const handleToggleStarship = () => {
    const activating = !isStarshipActive;
    setIsStarshipActive(activating);
    if (activating) {
       setIsPaused(false);
       setSimulationSpeed(0.5); 
    } else {
       setSimulationSpeed(1.0);
    }
  };

  const handleMissionComplete = () => {
     setIsStarshipActive(false);
     setSimulationSpeed(1.0); 
  };

  const selectedPlanet = useMemo(() => {
    if (selectedPlanetId === 'sun') return SUN_DATA;
    // Check main planets
    const planet = PLANETS.find(p => p.id === selectedPlanetId);
    if (planet) return planet;
    // Check Jupiter's moons
    return JUPITER_MOONS.find(m => m.id === selectedPlanetId) || null;
  }, [selectedPlanetId]);

  const displayedPlanets = useMemo(() => {
    return showPluto ? PLANETS : PLANETS.filter(p => p.id !== 'pluto');
  }, [showPluto]);

  return (
    <div className="w-full h-screen relative overflow-hidden transition-colors duration-500"
         style={{ backgroundColor: isARMode ? 'transparent' : '#000' }}
    >

      <UIOverlay 
        selectedPlanet={selectedPlanet}
        onClose={handleClose}
        isPaused={isPaused}
        togglePause={() => setIsPaused(!isPaused)}
        simulationSpeed={simulationSpeed}
        setSimulationSpeed={setSimulationSpeed}
        isStarshipActive={isStarshipActive}
        toggleStarship={handleToggleStarship}
        showPluto={showPluto}
        togglePluto={togglePluto}
        isGestureMode={isGestureMode}
        toggleGestureMode={toggleGestureMode}
      />

      {isGestureMode && (
        <GestureController 
          onControl={handleGestureControl} 
          onClose={() => toggleGestureMode()} 
          isARMode={isARMode}
          toggleARMode={() => setIsARMode(!isARMode)}
        />
      )}

      {/* 
         Canvas needs alpha: true for transparency.
         When AR Mode is ON, we hide the Skybox and opaque layers so the video behind shows through.
         onPointerMissed handles clicking empty space to deselect/close popups.
      */}
      <Canvas 
        gl={{ antialias: true, toneMappingExposure: 1.2, alpha: true }}
        onPointerMissed={() => {
          // If we clicked on empty space (not a mesh), close the info panel
          if (selectedPlanetId) {
            handleClose();
          }
        }}
      >
        <Suspense fallback={null}>
          <PerspectiveCamera makeDefault position={[0, 80, 120]} fov={45} />

          <OrbitControls 
            ref={controlsRef}
            makeDefault
            enabled={!isStarshipActive} 
            enableDamping={true}
            dampingFactor={0.05}
            enablePan={false}
            minDistance={20}
            maxDistance={300}
            maxPolarAngle={Math.PI / 1.8}
            // Slower auto-rotate for better default experience
            autoRotate={!selectedPlanetId && !isPaused && !isGestureMode && !isStarshipActive}
            autoRotateSpeed={0.1 * simulationSpeed} 
          />

          <OrbitController controlsRef={controlsRef} gestureVelocity={gestureVelocity} />

          <Environment preset="city" environmentIntensity={0.3} />
          <pointLight position={[0, 0, 0]} intensity={2.5} distance={500} decay={1} color="#FFF5E0" />
          <ambientLight intensity={0.15} color="#404060" />

          {/* 1. Volumetric 3D Stars (Always show, they look nice floating in room) */}
          <Stars radius={400} depth={50} count={3000} factor={4} saturation={0.5} fade speed={0.5} />

          {/* 2. Painted Background (Skybox) - HIDE IN AR MODE */}
          {!isARMode && <Skybox />}

          {/* 3. Magical Dust */}
          <Sparkles count={400} scale={200} size={6} speed={0.2} opacity={0.4} noise={0.1} color="#88AAFF" />
          <Sparkles count={150} scale={150} size={3} speed={0.3} opacity={0.6} color="#FFD700" />

          <Sun 
             onSelect={handleSelect}
             isSelected={selectedPlanetId === 'sun'}
             isPaused={isPaused}
             simulationSpeed={simulationSpeed}
          />

          <AsteroidBelt isPaused={isPaused} simulationSpeed={simulationSpeed} />

          {displayedPlanets.map((planet) => (
            <Planet 
              key={planet.id} 
              data={planet} 
              isSelected={selectedPlanetId === planet.id}
              onSelect={handleSelect}
              isPaused={isPaused}
              simulationSpeed={simulationSpeed}
              earthPositionRef={earthPositionRef}
              planetRefs={planetRefs}
              isStarshipActive={isStarshipActive}
            />
          ))}

          {isStarshipActive && (
             <Starship 
                planetRefs={planetRefs} 
                onMissionComplete={handleMissionComplete}
             />
          )}

        </Suspense>
      </Canvas>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { FilesetResolver, HandLandmarker, HandLandmarkerResult } from '@mediapipe/tasks-vision';

interface GestureControllerProps {
  onControl: (dx: number, dy: number, gestureType: 'rotate' | 'zoom') => void;
  onClose: () => void;
  isARMode: boolean;
  toggleARMode: () => void;
}

type GuideStep = 'INIT' | 'DETECT_HAND' | 'CENTER_HAND' | 'TRY_MOVE' | 'COMPLETED';

export const GestureController: React.FC<GestureControllerProps> = ({ 
  onControl, 
  onClose,
  isARMode,
  toggleARMode
}) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const landmarkerRef = useRef<HandLandmarker | null>(null);
  const requestRef = useRef<number>(0);

  // Logic State
  const [guideStep, setGuideStep] = useState<GuideStep>('INIT');
  const [isLoading, setIsLoading] = useState(true);
  const [statusText, setStatusText] = useState("正在启动魔法引擎...");

  // Smoothing vars
  const cursorRef = useRef({ x: 0.5, y: 0.5 }); // Normalized 0-1
  const prevHandDistanceRef = useRef<number | null>(null);
  const lastGestureType = useRef<'rotate' | 'zoom'>('rotate');

  // --- 1. Initialization ---
  useEffect(() => {
    let isMounted = true;

    const init = async () => {
      try {
        const vision = await FilesetResolver.forVisionTasks(
          "https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.8/wasm"
        );

        if (!isMounted) return;

        landmarkerRef.current = await HandLandmarker.createFromOptions(vision, {
          baseOptions: {
            modelAssetPath: `https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/1/hand_landmarker.task`,
            delegate: "GPU"
          },
          runningMode: "VIDEO",
          numHands: 2,
          minHandDetectionConfidence: 0.6, // Higher confidence to reduce flicker
          minHandPresenceConfidence: 0.6,
          minTrackingConfidence: 0.6
        });

        if (isMounted) startWebcam();
      } catch (error) {
        console.error("Error initializing MediaPipe:", error);
        if (isMounted) {
          setIsLoading(false);
          setStatusText("启动失败，请刷新试试");
        }
      }
    };

    init();

    return () => {
      isMounted = false;
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, []);

  const startWebcam = async () => {
    if (!videoRef.current) return;
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { width: 640, height: 480, facingMode: "user" } 
      });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        videoRef.current.onloadeddata = () => {
          setIsLoading(false);
          setGuideStep('DETECT_HAND'); // Start Guide
          predictWebcam();
        };
      }
    } catch (err) {
      console.error(err);
      setStatusText("请允许摄像头权限哦");
      setIsLoading(false);
    }
  };

  // --- 2. Main Loop ---
  const predictWebcam = () => {
    if (!landmarkerRef.current || !videoRef.current || videoRef.current.readyState < 2) {
        requestRef.current = requestAnimationFrame(predictWebcam);
        return;
    }

    const startTimeMs = performance.now();
    const result = landmarkerRef.current.detectForVideo(videoRef.current, startTimeMs);

    // Process Logic
    handleGameLogic(result);

    // Draw Visuals
    drawCanvas(result);

    requestRef.current = requestAnimationFrame(predictWebcam);
  };

  // --- 3. Game Logic (The Brain) ---
  const handleGameLogic = (result: HandLandmarkerResult) => {
    const hands = result.landmarks;
    const count = hands.length;

    // --- GUIDE LOGIC ---
    if (guideStep !== 'COMPLETED') {
        onControl(0, 0, 'rotate'); // Stop world during guide

        if (guideStep === 'DETECT_HAND') {
            if (count > 0) {
                setStatusText("看到你了！👋");
                setTimeout(() => setGuideStep('CENTER_HAND'), 1000);
            } else {
                setStatusText("请对着镜头挥挥手 👋");
            }
        } else if (guideStep === 'CENTER_HAND') {
            const hand = hands[0];
            const x = 1.0 - hand[9].x; // Mirror
            const y = hand[9].y;
            // Check if in center box (0.35 - 0.65)
            if (x > 0.35 && x < 0.65 && y > 0.35 && y < 0.65) {
                setStatusText("太棒了！保持住 🎯");
                setTimeout(() => setGuideStep('TRY_MOVE'), 1500);
            } else {
                setStatusText("把手移到中间的方框里 🔲");
            }
        } else if (guideStep === 'TRY_MOVE') {
            const hand = hands[0];
            const x = 1.0 - hand[9].x;
            if (x < 0.3 || x > 0.7) {
                 setStatusText("成功！你学会了魔法！✨");
                 setTimeout(() => setGuideStep('COMPLETED'), 1500);
            } else {
                 setStatusText("试着把手向左或向右移动 👈👉");
            }
        }
        return;
    }

    // --- ACTIVE CONTROL LOGIC ---
    if (count === 0) {
        onControl(0, 0, 'rotate');
        prevHandDistanceRef.current = null;
        setStatusText("找不到小手了... 👀");
        return;
    }

    // Two Hands = Zoom
    if (count === 2) {
        const h1 = hands[0][9];
        const h2 = hands[1][9];
        const dist = Math.hypot(h1.x - h2.x, h1.y - h2.y);

        if (prevHandDistanceRef.current !== null) {
            const delta = dist - prevHandDistanceRef.current;
            if (Math.abs(delta) > 0.005) { // Sensitivity threshold
                onControl(0, delta * 350, 'zoom'); // Slower zoom
                setStatusText(delta > 0 ? "正在变大 (Zoom In)" : "正在变小 (Zoom Out)");
                lastGestureType.current = 'zoom';
            } else {
                onControl(0, 0, 'zoom');
            }
        }
        prevHandDistanceRef.current = dist;
        return;
    }

    // One Hand = Rotate (Joystick Mode)
    if (count === 1) {
        prevHandDistanceRef.current = null; // Reset zoom state

        const hand = hands[0];
        const rawX = 1.0 - hand[9].x; // Mirroring
        const rawY = hand[9].y;

        // Smooth cursor
        cursorRef.current.x += (rawX - cursorRef.current.x) * 0.2;
        cursorRef.current.y += (rawY - cursorRef.current.y) * 0.2;

        const cx = cursorRef.current.x;
        const cy = cursorRef.current.y;

        // Joystick Deadzone Logic
        // Center: 0.5. Deadzone: 0.4 - 0.6 (size 0.2)
        const DEADZONE = 0.15; // 15% from center
        const CENTER = 0.5;

        let dx = 0;
        let dy = 0;

        // X Axis
        if (cx < CENTER - DEADZONE) dx = (cx - (CENTER - DEADZONE)) * 2.5; // Move Left (Negative)
        else if (cx > CENTER + DEADZONE) dx = (cx - (CENTER + DEADZONE)) * 2.5; // Move Right (Positive)

        // Y Axis (Inverted: Up hand = Up Camera angle = positive dy logic usually, depends on OrbitControls)
        if (cy < CENTER - DEADZONE) dy = (cy - (CENTER - DEADZONE)) * 2.5;
        else if (cy > CENTER + DEADZONE) dy = (cy - (CENTER + DEADZONE)) * 2.5;

        // Send Control
        if (dx !== 0 || dy !== 0) {
            onControl(dx, dy, 'rotate');
            lastGestureType.current = 'rotate';

            // Simple visual feedback
            if (Math.abs(dx) > Math.abs(dy)) {
                setStatusText(dx > 0 ? "向右转 👉" : "👈 向左转");
            } else {
                setStatusText(dy > 0 ? "向下看 👇" : "👆 向上看");
            }
        } else {
            onControl(0, 0, 'rotate');
            if (lastGestureType.current === 'rotate') {
                setStatusText("✋ 暂停中 (移出方框来旋转)");
            }
        }
    }
  };

  // --- 4. Drawing (The UI) ---
  const drawCanvas = (result: HandLandmarkerResult) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Clear and Match Video Size
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Draw Deadzone Box
    const deadzoneSize = 0.3; // 30% width
    const boxX = canvas.width * (0.5 - deadzoneSize/2);
    const boxY = canvas.height * (0.5 - deadzoneSize/2);
    const boxW = canvas.width * deadzoneSize;
    const boxH = canvas.height * deadzoneSize;

    // Box Style
    ctx.strokeStyle = "rgba(255, 255, 255, 0.5)";
    ctx.lineWidth = 2;
    ctx.setLineDash([10, 10]);
    ctx.strokeRect(boxX, boxY, boxW, boxH);
    ctx.setLineDash([]);

    // Guide Text in Box
    if (guideStep === 'CENTER_HAND' || guideStep === 'COMPLETED') {
        ctx.fillStyle = "rgba(255,255,255,0.3)";
        ctx.font = "16px sans-serif";
        ctx.textAlign = "center";
        ctx.fillText("暂停区", canvas.width/2, canvas.height/2 + 6);
    }

    // Draw Hand Cursor
    if (result.landmarks && result.landmarks.length > 0) {
        // We only really care about the first hand for the cursor
        const cx = cursorRef.current.x * canvas.width;
        const cy = cursorRef.current.y * canvas.height;

        // Is it inside the box?
        const isStopped = cx > boxX && cx < boxX + boxW && cy > boxY && cy < boxY + boxH;

        // Draw Cute Cursor
        ctx.beginPath();
        ctx.arc(cx, cy, 15, 0, 2 * Math.PI);
        ctx.fillStyle = isStopped ? "#4ade80" : "#fbbf24"; // Green if stopped, Orange if moving
        ctx.fill();
        ctx.strokeStyle = "white";
        ctx.lineWidth = 3;
        ctx.stroke();

        // Draw "Direction Line" if moving
        if (!isStopped) {
            ctx.beginPath();
            ctx.moveTo(canvas.width/2, canvas.height/2);
            ctx.lineTo(cx, cy);
            ctx.strokeStyle = "rgba(251, 191, 36, 0.5)";
            ctx.lineWidth = 4;
            ctx.stroke();
        }

        // Draw Hand Skeleton (Subtle)
        for (const landmarks of result.landmarks) {
             drawSkeleton(ctx, landmarks, canvas.width, canvas.height);
        }
    }
  };

  const drawSkeleton = (ctx: CanvasRenderingContext2D, landmarks: any[], w: number, h: number) => {
      ctx.lineWidth = 2;
      ctx.strokeStyle = "rgba(0, 255, 255, 0.3)";
      ctx.fillStyle = "rgba(0, 255, 255, 0.3)";

      // Connections
      const connections = HandLandmarker.HAND_CONNECTIONS;
      for (const conn of connections) {
          const s = landmarks[conn.start];
          const e = landmarks[conn.end];
          // Mirror x
          ctx.beginPath();
          ctx.moveTo((1-s.x)*w, s.y*h);
          ctx.lineTo((1-e.x)*w, e.y*h);
          ctx.stroke();
      }
      // Points
      for (const lm of landmarks) {
          ctx.beginPath();
          ctx.arc((1-lm.x)*w, lm.y*h, 3, 0, 2*Math.PI);
          ctx.fill();
      }
  }

  // --- Render ---
  return (
    <>
      {/* 
        Full Screen Video for AR Mode 
        Hidden via opacity if not AR, but kept for Logic
      */}
      <video 
        ref={videoRef}
        className={`fixed inset-0 w-full h-full object-cover -scale-x-100 transition-all duration-500
            ${isARMode ? 'opacity-100 z-[-10]' : 'opacity-0 z-[-20] pointer-events-none'}
        `}
        autoPlay playsInline muted
      />

      {isARMode && <div className="fixed inset-0 bg-blue-900/30 z-[-9]" />}

      {/* 
        The "Magic Mirror" Canvas - Main UI for Kids 
        Always visible in Gesture Mode
      */}
      <div className={`fixed bottom-4 right-4 z-50 flex flex-col items-end gap-3 transition-all duration-500
          ${guideStep !== 'COMPLETED' ? 'bottom-1/2 translate-y-1/2 right-1/2 translate-x-1/2 scale-125' : ''}
      `}>

         {/* Status Bubble */}
         <div className="bg-white/90 text-slate-800 px-5 py-3 rounded-full font-bold shadow-xl border-2 border-cyan-400 flex items-center gap-2 animate-bounce-slight text-lg whitespace-nowrap">
            <span className="text-2xl">{statusText.includes("停") ? "✋" : statusText.includes("转") ? "✨" : "🤖"}</span>
            {statusText}
         </div>

         {/* The Canvas Display */}
         <div className="relative rounded-2xl overflow-hidden border-4 border-white/50 shadow-2xl bg-black/60 backdrop-blur-sm">
             <canvas 
                ref={canvasRef}
                width={320}
                height={240}
                className="-scale-x-100 block" // Mirror display logic matches drawing logic
             />

             {/* Overlay Video for "Mini Mode" visibility */}
             {!isARMode && (
                <video 
                  ref={(node) => {
                      // Reuse the main stream for this mini-view if possible, 
                      // or just rely on canvas drawing. 
                      // Actually, let's just draw the video on the canvas in drawCanvas for simplicity!
                      // See line: ctx.drawImage(videoRef.current...) below in drawCanvas update.
                  }}
                  className="hidden" // We draw frame-by-frame on canvas instead
                /> 
             )}

             {/* Guide Overlay Text */}
             {guideStep !== 'COMPLETED' && (
                 <div className="absolute inset-0 flex items-center justify-center bg-black/40 text-white font-bold text-center p-4">
                    {guideStep === 'DETECT_HAND' && "请把手举起来 👋"}
                    {guideStep === 'CENTER_HAND' && "把小手放到框框里"}
                    {guideStep === 'TRY_MOVE' && "左右挥手试一试！"}
                 </div>
             )}
         </div>

         {/* Controls */}
         {guideStep === 'COMPLETED' && (
             <div className="flex gap-2">
                 <button 
                   onClick={toggleARMode}
                   className="bg-cyan-500 hover:bg-cyan-400 text-white px-4 py-2 rounded-full font-bold shadow-lg text-sm border-2 border-white/30"
                 >
                    {isARMode ? "关闭背景" : "开启透视 (AR)"}
                 </button>
                 <button 
                   onClick={onClose}
                   className="bg-red-500 hover:bg-red-400 text-white w-10 h-10 rounded-full font-bold shadow-lg border-2 border-white/30 flex items-center justify-center"
                 >
                    ✕
                 </button>
             </div>
         )}
      </div>
    </>
  );
};

