                                // Height calculation for "rising" effect
                                const heightClass = ['h-3', 'h-4', 'h-6', 'h-8', 'h-10'][idx];
                                const activeColor = speed === 0 ? 'bg-red-500 shadow-[0_0_10px_#ef4444]' :
