                                            ${isActive ? 'opacity-100 text-white drop-shadow-md' : 'opacity-0 text-cyan-200 group-hover/btn:opacity-100'}`}>
                                          {speed === 0 ? 'STOP' : speed}
                                        </span>
                                    </button>
                                )
                            })}
                        </div>
                    </div>
                </div>
            </div>

          </div>
        </header>

        {/* Planet Info Card (Right Side) */}
        {selectedPlanet && (
