    case 'pluto':
      const plutoBase = colors[0]; 
      const plutoDark = colors[1]; 
      const plutoHeart = colors[2]; 
      svgContent = `<rect width="100%" height="100%" fill="${plutoBase}" />`;
      for (let i = 0; i < 20; i++) {
          const cx = Math.random() * width;
