/**
 * Generates a simple China Flag texture for Tiangong.
 */
export const generateChinaFlagTexture = (): string => {
  const width = 300;
  const height = 200;

  const starPath = (cx: number, cy: number, r: number, rot: number = 0) => {
     let d = "";
     for (let i = 0; i < 5; i++) {
        const theta = (Math.PI * 2 * i) / 5 - Math.PI / 2 + rot;
        const x = cx + Math.cos(theta) * r;
        const y = cy + Math.sin(theta) * r;
        d += (i === 0 ? "M" : "L") + `${x} ${y} `;

        // Inner point
        const thetaInner = theta + Math.PI / 5;
        const rInner = r * 0.382;
        const xi = cx + Math.cos(thetaInner) * rInner;
        const yi = cy + Math.sin(thetaInner) * rInner;
        d += `L ${xi} ${yi} `;
     }
     return d + "Z";
  };

  // Coordinates based on grid of 30x20
  const u = height / 20; 
  // Big star at (5, 5), radius 3
  const bigStar = starPath(5 * u, 5 * u, 3 * u);

  // 4 small stars
  const s1 = starPath(10 * u, 2 * u, 1 * u, Math.atan2(5-2, 5-10) + Math.PI/2);
  const s2 = starPath(12 * u, 4 * u, 1 * u, Math.atan2(5-4, 5-12) + Math.PI/2);
  const s3 = starPath(12 * u, 7 * u, 1 * u, Math.atan2(5-7, 5-12) + Math.PI/2);
  const s4 = starPath(10 * u, 9 * u, 1 * u, Math.atan2(5-9, 5-10) + Math.PI/2);

  const svgContent = `
    <rect width="100%" height="100%" fill="#DE2910" />
    <path d="${bigStar}" fill="#FFDE00" />
    <path d="${s1}" fill="#FFDE00" />
    <path d="${s2}" fill="#FFDE00" />
    <path d="${s3}" fill="#FFDE00" />
    <path d="${s4}" fill="#FFDE00" />
  `;

  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}">${svgContent}</svg>`;
  return `data:image/svg+xml;base64,${btoa(unescape(encodeURIComponent(svg)))}`;
};

/**
 * Generates a simple star field texture for the skybox background.
 */
export const generateStarFieldTexture = (): string => {
    const width = 1024;
    const height = 1024;

    let stars = '';
    for(let i=0; i<800; i++) {
        const x = Math.random() * width;
        const y = Math.random() * height;
        const r = Math.random() * 1.5 + 0.1;
        const op = Math.random() * 0.8 + 0.2;
        stars += `<circle cx="${x}" cy="${y}" r="${r}" fill="white" opacity="${op}" />`;
    }

    const svgContent = `
        <rect width="100%" height="100%" fill="#000000" />
        ${stars}
    `;

    const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}">${svgContent}</svg>`;
    return `data:image/svg+xml;base64,${btoa(unescape(encodeURIComponent(svg)))}`;
};
